{"path":"/tmp/faltest/render_ep001_4cut.mjs","content":"import { fal } from '@fal-ai/client';
import fs from 'fs';
import path from 'path';

const REPO = '/home/orbibot/.zeroclaw/workspace/awesome-novel-studio';
const PROJECT = path.join(REPO, 'projects/orbi-halfdrop-contract');
const EP_DIR = path.join(PROJECT, 'webtoon/ep001');
const RENDERS_DIR = path.join(EP_DIR, 'renders');
const REFS_CHAR_DIR = path.join(PROJECT, 'refs/characters');
const REFS_LOC_DIR = path.join(PROJECT, 'refs/locations');
const RESULTS_JSON = path.join(EP_DIR, 'fal_run_results.json');

for (const dir of [RENDERS_DIR, REFS_CHAR_DIR, REFS_LOC_DIR]) {
  fs.mkdirSync(dir, { recursive: true });
}

if (!process.env.FAL_KEY) {
  throw new Error('FAL_KEY is required');
}

fal.config({ credentials: process.env.FAL_KEY });

const objectLifecycle = { expiresIn: '7d' };

async function downloadToFile(url, outPath) {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to download ${url}: ${res.status}`);
  const arrayBuffer = await res.arrayBuffer();
  fs.writeFileSync(outPath, Buffer.from(arrayBuffer));
}

async function uploadPng(filePath) {
  const blob = new Blob([fs.readFileSync(filePath)], { type: 'image/png' });
  return fal.storage.upload(blob, { lifecycle: objectLifecycle });
}

function buildPrompt(core, negative = '') {
  const avoid = negative
    ? ` Avoid: ${negative.replace(/\.$/, '')}.`
    : '';
  return `${core}${avoid} No readable text, no speech bubbles, grounded Orbi admissions realism.`;
}

async function runT2I(name, prompt, outputPath, seed) {
  console.log(`\n[fal] text-to-image: ${name}`);
  const result = await fal.subscribe('fal-ai/flux-2-pro', {
    input: {
      prompt,
      image_size: 'portrait_16_9',
      output_format: 'png',
      seed,
      safety_tolerance: '2',
      enable_safety_checker: true,
      sync_mode: false,
    },
    storageSettings: objectLifecycle,
    onQueueUpdate(update) {
      if (update.status === 'IN_QUEUE') console.log(`[queue] ${name}: pos=${update.queue_position}`);
      else console.log(`[queue] ${name}: ${update.status}`);
    },
  });
  const image = result.data.images?.[0];
  if (!image?.url) throw new Error(`No image URL returned for ${name}`);
  await downloadToFile(image.url, outputPath);
  return { seed: result.data.seed, url: image.url, path: outputPath };
}

async function runEdit(name, prompt, imageUrls, outputPath, seed) {
  console.log(`\n[fal] image-edit: ${name}`);
  const result = await fal.subscribe('fal-ai/flux-2-pro/edit', {
    input: {
      prompt,
      image_urls: imageUrls,
      image_size: 'portrait_16_9',
      output_format: 'png',
      seed,
      safety_tolerance: '2',
      enable_safety_checker: true,
      sync_mode: false,
    },
    storageSettings: objectLifecycle,
    onQueueUpdate(update) {
      if (update.status === 'IN_QUEUE') console.log(`[queue] ${name}: pos=${update.queue_position}`);
      else console.log(`[queue] ${name}: ${update.status}`);
    },
  });
  const image = result.data.images?.[0];
  if (!image?.url) throw new Error(`No image URL returned for ${name}`);
  await downloadToFile(image.url, outputPath);
  return { seed: result.data.seed, url: image.url, path: outputPath };
}

const yoonAnchorPath = path.join(REFS_CHAR_DIR, 'yoon_seojin_ep001_anchor.png');
const locationAnchorPath = path.join(REFS_LOC_DIR, 'selfstudy_room_night_ep001_anchor.png');

const outputs = { anchors: {}, panels: {} };

async function main() {
  outputs.anchors.location = await runT2I(
    'location-anchor',
    buildPrompt(
      'A narrow Korean self-study room late at night, cramped desk booths with muted partitions, stacks of exam prep books, mechanical pencil, smartphone glow, cold fluorescent lighting, quiet oppressive atmosphere around 2 AM, grounded realism, Korean admissions-thriller tone, vertical webtoon location anchor, no people required',
      'cozy cafe, luxury study lounge, warm sunset light, neon lighting, gaming setup, fantasy environment'
    ),
    locationAnchorPath,
    42001,
  );

  outputs.anchors.yoon = await runT2I(
    'yoon-anchor',
    buildPrompt(
      'A tired Korean male university-age retaker with a thin build, sleep-deprived eyes, neat dark hair, thin dark glasses, wearing a muted campus jacket or dark hoodie, seated in a narrow late-night self-study room, restrained emotion, cold fluorescent lighting, Korean admissions-thriller tone, vertical webtoon character anchor',
      'school uniform, flashy idol styling, exaggerated handsome face, no glasses, fantasy lighting, smiley cheerful expression'
    ),
    yoonAnchorPath,
    42002,
  );

  const locationUrl = await uploadPng(locationAnchorPath);
  const yoonUrl = await uploadPng(yoonAnchorPath);

  outputs.anchors.uploaded = { locationUrl, yoonUrl };

  outputs.panels.P01 = await runEdit(
    'P01',
    buildPrompt(
      'Compose the opening panel of a Korean vertical webtoon scene using the same self-study room and the same male student. He sits at the cramped desk late at night with a problem book open, smartphone vibrating with repeated community alerts, tense stillness before checking the screen. Keep the same glasses, same thin build, same wardrobe, same cold fluorescent lighting, and same booth geometry. Close-up on desk with partial face reveal, slightly high angle.',
      'visible Korean text, speech bubbles, fantasy styling, wrong school setting'
    ),
    [locationUrl, yoonUrl],
    path.join(RENDERS_DIR, 'P01.png'),
    41001,
  );

  const p01Url = await uploadPng(outputs.panels.P01.path);
  outputs.panels.P02 = await runEdit(
    'P02',
    buildPrompt(
      'Continue the exact same scene with the same student in the same booth. Extreme close-up of his tired eyes with an anonymous admissions ranking chart reflected in his glasses. Preserve face identity, glasses shape, room identity, and cold fluorescent reflection pattern. Keep it grounded and psychologically tense.',
      'identity drift, different glasses, different wardrobe, readable chart text, random letters'
    ),
    [p01Url, yoonUrl, locationUrl],
    path.join(RENDERS_DIR, 'P02.png'),
    41001,
  );

  const p02Url = await uploadPng(outputs.panels.P02.path);
  outputs.panels.P03 = await runEdit(
    'P03',
    buildPrompt(
      'Continue the same scene with the same student at the same desk. Over-the-shoulder phone shot, thumb paused above the keyboard after typing and deleting a reply. Preserve face identity, hand tone, phone, desk layout, booth geometry, and fluorescent palette. The mood is tense and restrained, not melodramatic.',
      'identity drift, different hand or phone, readable chat text, emoji overload'
    ),
    [p02Url, yoonUrl, locationUrl],
    path.join(RENDERS_DIR, 'P03.png'),
    41001,
  );

  const p03Url = await uploadPng(outputs.panels.P03.path);
  outputs.panels.P04 = await runEdit(
    'P04',
    buildPrompt(
      'Continue the same booth scene with the same Korean male retaker. Smartphone message from his father about a contract department consultation appears in his hand, and the student reacts with restrained pressure. Preserve face, glasses, phone hand, booth position, room identity, and same night fluorescent palette. Split-focus insert on phone and face, psychologically realistic.',
      'identity drift, readable message text, melodramatic tears, fantasy effects'
    ),
    [p03Url, yoonUrl, locationUrl],
    path.join(RENDERS_DIR, 'P04.png'),
    41001,
  );

  fs.writeFileSync(RESULTS_JSON, JSON.stringify(outputs, null, 2));
  console.log(`\nSaved results metadata to ${RESULTS_JSON}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
"}

